#[tokio::test]
async fn test_batch_invoke_cycle_detection() {
    // Circular dependencies are rejected
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({}), depends_on: vec!["op2".into()] },
            BatchOperation { id: "op2".into(), tool: "test.echo".into(), input: json!({}), depends_on: vec!["op1".into()] },
